    data A,B;
    Seg(){}
    Seg(data A,data B):A(A),B(B){}
};
struct Line{//用点值+方向（法度）表示法 
    double a,b,c;
    Line(){}
    Line(data A,data B){a=B.y-A.y;b=A.x-B.x;c=(B.x-A.x)*A.y-(B.y-A.y)*A.x;}
};
struct Cir{//点+半径 
    data c;
    double r;
    Cir(){}
    Cir(data c,double r):c(c),r(r){}
};
