        if(!OnCir(t,C[i]))INsert(t,i);
    }
    for(register int i=1;i<=cnt;i++){
        for(register int j=i+1;j<=cnt;j++){
            flag=1;
            for(register int k=1;k<=tot;k++){//切线与公切线 
                if(JX(Seg(V[i],V[j]),S[k])||CrCir(Seg(V[i],V[j]),C[k]))flag=0;
