            }
            if(flag)Addedge(i,j,dist(V[i],V[j]));
        }
    }
    SPFA();
    if(N==0)
    {
    	cout<<"0.00";
	}
	else
	{
		printf("%.2lf\n",dis[2]);	
	} 
    return 0;
